$(function () {
  $("#buat-job").click(function (a) {
    a.preventDefault(),
      Swal.fire({
        title: "Backup Inkremental",
        text: "Backup Inkremental membutuhkan resource yang besar dan membuat akses ke aplikasi menjadi lambat. Disarankan menjalankan backup Inkremental disaat aplikasi tidak di akses.",
        footer:
          '<div class="text-bold text-center text-red">Backup Inkremental akan berjalan di belakang layar dan tidak bisa dibatalkan sampai proses selesai</div>',
        icon: "warning",
        showCancelButton: !0,
        confirmButtonText: "Lanjutkan",
      }).then((a) => {
        a.isConfirmed &&
          Swal.fire({
            title: "Lokasi Simpan",
            showDenyButton: !0,
            showCancelButton: !1,
            confirmButtonText: "Temporary folder",
            denyButtonText: "Backup folder",
            footer: `
                        <div class="text-bold text-warning">
                            <ul>
                                <li>Temporary folder : file backup akan terhapus otomatis oleh sistem</li>
                                <li>folder backup : file backup akan disimpan di dalam folder backup_inkremental dan tidak akan dihapus oleh sistem. </li>
                            </ul>
                        </div>
                        `,
          }).then((a) => {
            if (a.isConfirmed) e("null");
            else {
              if (!a.isDenied) return;
              e("backup");
            }
          });
      });
  });
  var e = function (e) {
    notification("success", "Backup Sedang Dalam Proses"),
      $("#Inkremental")
        .html('<i class="fa fa-download"></i> Backup Dalam Proses')
        .addClass("btn-warning"),
      $("button.dropdown-toggle").addClass("btn-warning"),
      $("#Inkremental")
        .parent()
        .find("ul")
        .append(
          "<li><a href=\"<?= site_url('database/batal_backup'); ?>\">Batalkan Proses Backup</a></li>",
        ),
      $.ajax({
        url: SITE_URL + "database/inkremental_job",
        type: "Post",
        data: { lokasi: e },
      })
        .done(function (e) {
          !0 == e.status
            ? $("#buat-job").remove()
            : (notification("danger", e.message),
              $("#Inkremental")
                .html('<i class="fa fa-download"></i> Backup Dalam Proses')
                .removeClass("btn-warning"),
              $("button.dropdown-toggle").removeClass("btn-warning"));
        })
        .fail(function (e) {
          notification("danger", e);
        });
  };
  $("#restore-desa").click(function (e) {
    Swal.fire({
      title: "Kirim Kode Verifikasi",
      showDenyButton: !0,
      showCancelButton: !1,
      confirmButtonText: "Email",
      cancelButtonText: "Tutup",
      denyButtonText: "Telegram",
      footer:
        '<div class="text-bold text-warning">Kode Verifikasi hanya berlaku 5 menit</div>',
    }).then((e) => {
      e.isConfirmed
        ? (Swal.fire({
            title: "Mengirim Kode Verifikasi Email",
            allowOutsideClick: !1,
            allowEscapeKey: !1,
            showConfirmButton: !1,
            didOpen() {
              Swal.showLoading();
            },
          }),
          $.ajax({
            url: SITE_URL + "database/kirim_otp",
            type: "POST",
            data: { sidcsrf: getCsrfToken(), method: "email" },
          })
            .done(function () {
              a();
            })
            .fail(function (e) {
              Swal.fire({
                icon: "error",
                title: "Oops...",
                text: `${e?.responseJSON?.message}`,
                footer: '<a href="' + SITE_URL + 'pengguna">Kembali ke halaman Pengguna</a>',
              });
            }))
        : e.isDenied &&
          (Swal.fire({
            title: "Mengirim Kode Verifikasi Telegram",
            allowOutsideClick: !1,
            allowEscapeKey: !1,
            showConfirmButton: !1,
            didOpen() {
              Swal.showLoading();
            },
          }),
          $.ajax({
            url: SITE_URL + "database/kirim_otp",
            type: "POST",
            data: { sidcsrf: getCsrfToken(), method: "telegram" },
          })
            .done(function () {
              a();
            })
            .fail(function (e) {
              Swal.fire({
                icon: "error",
                title: "Oops...",
                text: `${e?.responseJSON?.message}`,
                footer: '<a href="' + SITE_URL + 'pengguna">Kembali ke halaman Pengguna</a>',
              });
            }));
    });
  });
  var a = function () {
      Swal.fire({
        title: "Masukan Kode Verifikasi",
        input: "text",
        inputPlaceholder: "Masukan Kode Verifikasi",
        inputValidator(e) {
          if (isNaN(e)) return "Kode Verifikasi harus berupa angka";
        },
        showCancelButton: !0,
        confirmButtonText: "Kirim",
        cancelButtonText: "Tutup",
        showLoaderOnConfirm: !0,
        preConfirm(e) {
          let formData = new FormData();
          formData.append("sidcsrf", getCsrfToken());
          formData.append("otp", e);
          
          return $.ajax({
            url: SITE_URL + "database/verifikasi_otp",
            type: "POST",
            data: formData,
            processData: false,
            contentType: false,
            dataType: "json",
          })
            .fail(function (error) {
              Swal.showValidationMessage(`Request failed: ${error.statusText}`);
            });
        },
      }).then((e) => {
        e.isConfirmed &&
          (!0 == e.value.status
            ? t()
            : Swal.fire({ icon: "error", title: e.value.message }));
      });
    },
    t = function () {
      let e = new FormData();
      e.append("sidcsrf", getCsrfToken()),
        e.append("file", $("#file1")[0].files[0]),
        // Opsi "Pertahankan kredensial lokal" — dikirim ke upload_restore agar
        // restore folder desa mempertahankan config/database.php & app_key lokal.
        e.append("paksa_restore_desa", $("#paksa_restore_desa").is(":checked") ? "Y" : "N"),
        Swal.fire({
          title: "Sedang mengunggah file",
          html: "Progress : <b></b>%",
          timerProgressBar: !0,
          didOpen() {
            Swal.showLoading();
            let a = Swal.getHtmlContainer().querySelector("b");
            $.ajax({
              xhr: function () {
                var e = new window.XMLHttpRequest();
                return (
                  e.upload.addEventListener(
                    "progress",
                    function (e) {
                      if (e.lengthComputable) {
                        var t = e.loaded / e.total;
                        (t = parseInt(100 * t)), (a.textContent = t);
                      }
                    },
                    !1,
                  ),
                  e
                );
              },
              url: SITE_URL + "database/upload_restore",
              type: "POST",
              data: e,
              processData: !1,
              contentType: !1,
              success: function (e) {
                !0 == e.status
                  ? pollRestoreStatus()
                  : Swal.fire({
                      title: "Proses restore gagal",
                      icon: "error",
                      html: e.message,
                    });
              },
            }).fail(function (e) {
              e.responseText,
                Swal.fire({
                  title: "Proses upload gagal",
                  icon: "warning",
                  html: e.responseText,
                });
            });
          },
        });
    };

  // Polling status restore folder desa: tampilkan notifikasi saat job background
  // selesai/gagal tanpa perlu refresh manual (status via database/status_restore).
  function pollRestoreStatus() {
    var pollInterval;
    var tickInterval;
    var completed = false;
    var elapsed = 0;
    var countdown = 5;

    Swal.fire({
      title: "Restore sedang berjalan",
      html:
        "Proses restore folder desa sedang berjalan di background.<br><br>" +
        "Anda dapat melanjutkan aktivitas lain. Kembali ke halaman <strong>Database</strong> untuk melihat statusnya.<br><br>" +
        "<small class='text-muted'>Memeriksa status dalam <strong><span id='restore-countdown'>5</span></strong> detik" +
        " &mdash; sudah berjalan <span id='restore-elapsed'>0</span> detik.</small>",
      allowOutsideClick: true,
      allowEscapeKey: true,
      showConfirmButton: true,
      confirmButtonText: "Lanjutkan bekerja",
      didOpen: function () {
        function doCheck() {
          countdown = 5;
          $.ajax({
            url: SITE_URL + "database/status_restore",
            type: "GET",
          }).done(function (res) {
            if (res.status === 1) {
              clearInterval(pollInterval);
              clearInterval(tickInterval);
              completed = true;
              Swal.fire({
                title: "Restore Selesai",
                icon: "success",
                html: res.message,
              }).then(function () {
                window.location = SITE_URL + "database";
              });
            } else if (res.status === -1 || res.status === 3) {
              clearInterval(pollInterval);
              clearInterval(tickInterval);
              completed = true;
              Swal.fire({
                title: "Restore Gagal",
                icon: "error",
                html: res.message,
              }).then(function () {
                window.location = SITE_URL + "database";
              });
            }
          });
        }

        tickInterval = setInterval(function () {
          elapsed++;
          countdown = Math.max(0, countdown - 1);
          var cdEl = document.getElementById("restore-countdown");
          var elEl = document.getElementById("restore-elapsed");
          if (cdEl) cdEl.textContent = countdown;
          if (elEl) elEl.textContent = elapsed;
        }, 1000);

        doCheck();
        pollInterval = setInterval(doCheck, 5000);
      },
      willClose: function () {
        clearInterval(pollInterval);
        clearInterval(tickInterval);
        if (!completed) {
          window.location = SITE_URL + "database";
        }
      },
    });
  }
});
